$(document).ready(function(){function showSelectedElectiveContent(selectedValue){if(selectedValue){$(".elective-tabcontent").hide();$("#"+selectedValue).show();$("#"+selectedValue+"-1").show()}}
var currentUrl=window.location.href.toLowerCase();var urlToElectiveMap={"digital-marketing":{value:"elec-dm",name:"Digital Marketing"},finance:{value:"elec-finance",name:"Finance"},marketing:{value:"elec-marketing",name:"Marketing"},"human-resource-management":{value:"elec-hrm",name:"HRM"},"analytics-data-science":{value:"elec-analytics",name:"Analytics & DS",},"banking-financial-services-insurance":{value:"elec-bfsi",name:"BFSI",},"it-fintech":{value:"elec-it",name:"IT & FinTech"},"operations-management":{value:"elec-op",name:"Operations Management",},"international-business":{value:"elec-ib",name:"International Business",},"information-system-management":{value:"elec-ism",name:"Information System Management",},"project-management":{value:"elec-pm",name:"Project Management"},"supply-chain-management":{value:"elec-scm",name:"Supply Chain Management",},"retail-management":{value:"elec-rm",name:"Retail Management"},};var currentElective=null;$.each(urlToElectiveMap,function(key,elective){if(currentUrl.indexOf(key)!==-1){currentElective=elective;return!1}});if(currentElective){if($(window).width()<992){var $electivesLayout=$(".course-curriculum .content")}else{var $electivesLayout=$(".semester-block")}
$electivesLayout.find("p.elective-title").remove();$electivesLayout.find(".right").html(`
      <div class="elective-display">
        <p class="elective-title">Electives/Specializations subjects</p>
      </div>
    `);$electivesLayout.find(".radio-btn").hide();showSelectedElectiveContent(currentElective.value)}else{$(".electives-layout p.title").text("Electives/Specializations subjects")}})